import { useEffect, useState } from "react";
import { useParams } from "react-router-dom";

import DeanLayout from "../../layouts/DeanLayout";

import {
  getFacultySubmissionById
} from "../../api/deanApi";

function DeanFacultyView() {

  const { id } = useParams();

  const [submission, setSubmission] = useState(null);

  const [loading, setLoading] = useState(true);

  useEffect(() => {

    loadSubmission();

  }, []);

  const loadSubmission = async () => {

    try {

      const res =
        await getFacultySubmissionById(id);

      setSubmission(
        res.data.submission
      );

    }

    catch (err) {

      console.error(err);

    }

    finally {

      setLoading(false);

    }

  };

  if (loading) {

    return (

      <DeanLayout>

        <div style={{ padding: "30px" }}>
          Loading...
        </div>

      </DeanLayout>

    );

  }

  if (!submission) {

    return (

      <DeanLayout>

        <div style={{ padding: "30px" }}>
          Submission Not Found
        </div>

      </DeanLayout>

    );

  }

  return (

    <DeanLayout>

      <div
        style={{
          padding: "30px"
        }}
      >

        <h1>

          Faculty Submission

        </h1>

        <br />

        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            background: "#fff"
          }}
        >

          <tbody>

            <tr>
              <td><b>Name</b></td>
              <td>{submission.submittedByName}</td>
            </tr>

            <tr>
              <td><b>Email</b></td>
              <td>{submission.submittedByEmail}</td>
            </tr>

            <tr>
              <td><b>School</b></td>
              <td>{submission.school}</td>
            </tr>

            <tr>
              <td><b>Department</b></td>
              <td>{submission.department}</td>
            </tr>

            <tr>
              <td><b>Quarter</b></td>
              <td>{submission.quarter}</td>
            </tr>

            <tr>
              <td><b>Status</b></td>
              <td>{submission.status}</td>
            </tr>

          </tbody>

        </table>

        <br />
        <br />

        <h2>

          Faculty Answers

        </h2>

        <table
          style={{
            width: "100%",
            borderCollapse: "collapse",
            background: "#fff"
          }}
        >

          <thead>

            <tr>

              <th style={thStyle}>Question No</th>

              <th style={thStyle}>Question</th>

              <th style={thStyle}>Answer</th>

            </tr>

          </thead>

          <tbody>

            {

              submission.answers.map(

                (answer, index) => (

                  <tr key={index}>

                    <td style={tdStyle}>
                      {answer.questionNo}
                    </td>

                    <td style={tdStyle}>
                      {answer.question}
                    </td>

                    <td style={tdStyle}>
                      {answer.answer}
                    </td>

                  </tr>

                )

              )

            }

          </tbody>

        </table>

      </div>

    </DeanLayout>

  );

}

const thStyle = {

  border: "1px solid #ddd",

  padding: "12px",

  background: "#2563eb",

  color: "#fff"

};

const tdStyle = {

  border: "1px solid #ddd",

  padding: "12px"

};

export default DeanFacultyView;
